from Crypto.Util.number import *
from secret import flag
from random import *
from Crypto.Util.Padding import pad
from Crypto.Cipher import AES

gift = b"".join(long_to_bytes((pow(getrandbits(4), 2*i, 17) & 0xf) ^ getrandbits(8), 1) for i in range(4567))
key = getrandbits(256).to_bytes(32, byteorder='big')
ct = AES.new(key, AES.MODE_ECB).encrypt(pad(flag.encode(), 16))

print(ct)
print("gift =", bytes_to_long(gift))

